4325       if (!FMF.noNaNs())
4326         Interested |= fcNan;
4327 
4328       KnownFPClass Known = computeLHSClass(Interested);
4329 
4330       // Positive or zero X >= 0.0 --> true
4331       // Positive or zero X <  0.0 --> false
4332       if ((FMF.noNaNs() || Known.isKnownNeverNaN()) &&
4333           Known.cannotBeOrderedLessThanZero())
4334         return Pred == FCmpInst::FCMP_OGE ? getTrue(RetTy) : getFalse(RetTy);
4335       break;
4336     }
4337     case FCmpInst::FCMP_UGE:
4338     case FCmpInst::FCMP_OLT: {
4339       FPClassTest Interested = KnownFPClass::OrderedLessThanZeroMask;
4340       KnownFPClass Known = computeLHSClass(Interested);
4341 
4342       // Positive or zero or nan X >= 0.0 --> true
4343       // Positive or zero or nan X <  0.0 --> false
4344       if (Known.cannotBeOrderedLessThanZero())
4345         return Pred == FCmpInst::FCMP_UGE ? getTrue(RetTy) : getFalse(RetTy);
4346       break;
4347     }
4348     default:
4349       break;
4350     }
4351   }
4352 
4353   // If the comparison is with the result of a select instruction, check whether
4354   // comparing with either branch of the select always yields the same value.
4355   if (isa<SelectInst>(LHS) || isa<SelectInst>(RHS))
4356     if (Value *V = threadCmpOverSelect(Pred, LHS, RHS, Q, MaxRecurse))
4357       return V;
4358 
4359   // If the comparison is with the result of a phi instruction, check whether
4360   // doing the compare with each incoming phi value yields a common result.
4361   if (isa<PHINode>(LHS) || isa<PHINode>(RHS))
4362     if (Value *V = threadCmpOverPHI(Pred, LHS, RHS, Q, MaxRecurse))
4363       return V;
4364 
4365   return nullptr;
4366 }
