2807 /// the correct element type.  We take the bytes in as a StringRef because
2808 /// we *want* an underlying "char*" to avoid TBAA type punning violations.
2809 Constant *ConstantDataSequential::getImpl(StringRef Elements, Type *Ty) {
2810 #ifndef NDEBUG
2811   if (ArrayType *ATy = dyn_cast<ArrayType>(Ty))
2812     assert(isElementTypeCompatible(ATy->getElementType()));
2813   else
2814     assert(isElementTypeCompatible(cast<VectorType>(Ty)->getElementType()));
2815 #endif
2816   // If the elements are all zero or there are no elements, return a CAZ, which
2817   // is more dense and canonical.
2818   if (isAllZeros(Elements))
2819     return ConstantAggregateZero::get(Ty);
2820 
2821   // Do a lookup to see if we have already formed one of these.
2822   auto &Slot =
2823       *Ty->getContext()
2824            .pImpl->CDSConstants.insert(std::make_pair(Elements, nullptr))
2825            .first;
2826 
2827   // The bucket can point to a linked list of different CDS's that have the same
2828   // body but different types.  For example, 0,0,0,1 could be a 4 element array
2829   // of i8, or a 1-element array of i32.  They'll both end up in the same
2830   /// StringMap bucket, linked up by their Next pointers.  Walk the list.
2831   std::unique_ptr<ConstantDataSequential> *Entry = &Slot.second;
2832   for (; *Entry; Entry = &(*Entry)->Next)
2833     if ((*Entry)->getType() == Ty)
2834       return Entry->get();
