2839     // Use reset because std::make_unique can't access the constructor.
2840     Entry->reset(new ConstantDataArray(Ty, Slot.first().data()));
2841     return Entry->get();
2842   }
2843 
2844   assert(isa<VectorType>(Ty));
2845   // Use reset because std::make_unique can't access the constructor.
2846   Entry->reset(new ConstantDataVector(Ty, Slot.first().data()));
