2659 Constant *ConstantExpr::getBinOpIdentity(unsigned Opcode, Type *Ty,
2660                                          bool AllowRHSConstant, bool NSZ) {
2661   assert(Instruction::isBinaryOp(Opcode) && "Only binops allowed");
2662 
2663   // Commutative opcodes: it does not matter if AllowRHSConstant is set.
2664   if (Instruction::isCommutative(Opcode)) {
2665     switch (Opcode) {
2666       case Instruction::Add: // X + 0 = X
2667       case Instruction::Or:  // X | 0 = X
2668       case Instruction::Xor: // X ^ 0 = X
2669         return Constant::getNullValue(Ty);
2670       case Instruction::Mul: // X * 1 = X
2671         return ConstantInt::get(Ty, 1);
2672       case Instruction::And: // X & -1 = X
2673         return Constant::getAllOnesValue(Ty);
2674       case Instruction::FAdd: // X + -0.0 = X
2675         return ConstantFP::getZero(Ty, !NSZ);
2676       case Instruction::FMul: // X * 1.0 = X
2677         return ConstantFP::get(Ty, 1.0);
2678       default:
2679         llvm_unreachable("Every commutative binop has an identity constant");
2680     }
2681   }
2682 
2683   // Non-commutative opcodes: AllowRHSConstant must be set.
2684   if (!AllowRHSConstant)
2685     return nullptr;
2686 
2687   switch (Opcode) {
2688     case Instruction::Sub:  // X - 0 = X
2689     case Instruction::Shl:  // X << 0 = X
2690     case Instruction::LShr: // X >>u 0 = X
2691     case Instruction::AShr: // X >> 0 = X
2692     case Instruction::FSub: // X - 0.0 = X
2693       return Constant::getNullValue(Ty);
2694     case Instruction::SDiv: // X / 1 = X
2695     case Instruction::UDiv: // X /u 1 = X
2696       return ConstantInt::get(Ty, 1);
2697     case Instruction::FDiv: // X / 1.0 = X
2698       return ConstantFP::get(Ty, 1.0);
2699     default:
2700       return nullptr;
2701   }
2702 }
