1812   // (X != MIN) && (X > Y) -->  X > Y
1813   // (X == MIN) || (X <= Y) --> X <= Y
1814   if (MinMaxC.isMinValue())
1815     if (Pred0 == ICmpInst::ICMP_NE && Pred1 == ICmpInst::ICMP_UGT)
1816       return Cmp1;
1817 
1818   return nullptr;
1819 }
